# Module providing data processing utilities with generic containers

class Doubler:
    @virtual
    def transform(self, x: int) -> int:
        return x * 2

class Tripler(Doubler):
    @override
    def transform(self, x: int) -> int:
        return x * 3

class DataStats:
    values: list[int]

    def __init__(self, items: list[int]):
        self.values = items

    def sum(self) -> int:
        total: int = 0
        for v in self.values:
            total = total + v
        return total

    def average(self) -> float:
        if len(self.values) == 0:
            return 0.0
        return float(self.sum()) / float(len(self.values))

def filter_positive(items: list[int]) -> list[int]:
    result: list[int] = []
    for item in items:
        if item > 0:
            result.append(item)
    return result

def apply_transform(processor: Doubler, value: int) -> int:
    return processor.transform(value)

class Incrementor:
    delta: int

    def __init__(self, delta: int):
        self.delta = delta

    def process(self, x: int) -> int:
        return x + self.delta

