# Module providing formatting utilities
from data_utils import DataStats

class Formatter:
    prefix: str

    def __init__(self, prefix: str):
        self.prefix = prefix

    def format_number(self, n: int) -> str:
        return self.prefix + str(n)

    def format_float(self, n: float) -> str:
        return self.prefix + str(n)

def create_summary(stats: DataStats) -> str:
    s: int = stats.sum()
    a: float = stats.average()
    return "Sum: " + str(s) + ", Avg: " + str(a)

def label_value(name: str, value: int) -> str:
    return name + "=" + str(value)
